<?phpnamespace App\Controller;use App\Entity\Authority;use App\Entity\KohUtilisateur;use App\Form\KohUtilisateurType;use App\Repository\AuthorityRepository;use App\Repository\KohUtilisateurRepository;use DateTime;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\IsGranted;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Swift_Mailer;use Swift_Message;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\RedirectResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;use Symfony\Component\Security\Core\Encoder\UserPasswordEncoderInterface;/** * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and !user.getIsKohUser() and user.getIsConfirmed()") * Class UtilisateurStructureController * @package App\Controller */class UtilisateurStructureController extends AbstractController{    /**     * @Route("/admin/structure/utilisateurs", name="admin.utilisateurs")     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return Response     */    public function structureUsers(KohUtilisateurRepository $kohUtilisateurRepository): Response    {        $users = $kohUtilisateurRepository->findByStructure($this->getUser()->getStructure()->getName());        return $this->render('utilisateur_structure/utilisateurs_structure.html.twig', ['koh_utilisateurs' => $users]);    }    /**     * @Route("/admin/structure/utilisateurs/new", name="admin.utilisateurs.new", methods={"GET", "POST"})     * @param Request $request     * @param AuthorityRepository $authorityRepository     * @param UserPasswordEncoderInterface $encoder     * @param Swift_Mailer $mailer     * @return Response     * @throws Exception     */    public function newUserStructure(Request $request, AuthorityRepository $authorityRepository, UserPasswordEncoderInterface $encoder, Swift_Mailer $mailer): Response    {        $kohUtilisateur = new KohUtilisateur();        $form = $this->createForm(KohUtilisateurType::class, $kohUtilisateur);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($kohUtilisateur);            $kohUtilisateur->setIsKohUser(false);            $random = $this->generate_string(100);            $kohUtilisateur->setConfirmationToken($random);            $kohUtilisateur->setIsConfirmed(false);            $kohUtilisateur->setIsActived(false);            $date = new DateTime('now', new DateTimeZone('GMT'));            $time = $date->getTimestamp() + (24 * 60 * 60);            $kohUtilisateur->setTokenValidity($time);            $kohUtilisateur->setStructure($this->getUser()->getStructure());            $kohUtilisateur->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')));            $kohUtilisateur->setStatus('non complete');            $kohUtilisateur->setStructure($this->getUser()->getStructure());            $kohUtilisateur->setNomStructure($this->getUser()->getStructure()->getName());            $kohUtilisateur->setIsAdmin(false);            $role = $authorityRepository->findOneBy(['name' => 'ADMIN']);            $kohUtilisateur->setTypeCompte($this->getUser()->getTypeCompte());            $kohUtilisateur->addAuthority($role);            $kohUtilisateur->setPassword($encoder->encodePassword($kohUtilisateur, $kohUtilisateur->getPassword()));            $entityManager->flush();            $message = (new Swift_Message("création de compte"))                ->setFrom('contact@mbeyan.com')                ->setTo($kohUtilisateur->getEmail())                ->setBody($this->renderView('mailer/registration.html.twig', ['firstName' => $kohUtilisateur->getFirstName(), 'lastName' => $kohUtilisateur->getLastName(), 'random' => $random, 'structure' => $kohUtilisateur->getStructure()]), 'text/html');            $mailer->send($message);            $this->addFlash('success', 'Le nouveau utilisateur a été enregistré');            return $this->redirectToRoute('admin.utilisateurs');        }        return $this->render('utilisateur_structure/new_utilisateur_structure.html.twig', ['form' => $form->createView()]);    }    /**     * @Route("/admin/structure/utilisateurs/activation-du-compte/{id}", name="admin.utilisateurs.active-user-account")     * @param KohUtilisateur $kohUtilisateur     * @return RedirectResponse     * @throws Exception     */    public function activationStructureUser(KohUtilisateur $kohUtilisateur): RedirectResponse    {        $kohUtilisateur->setIsActived(true);        $kohUtilisateur->setStatus('complete');        $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));        $this->getDoctrine()->getManager()->flush();        $this->addFlash('success', 'Le compte a été activé');        return $this->redirectToRoute('admin.utilisateurs');    }    /**     * @Route("/admin/structure/utilisateurs/desactivation-du-compte/{id}", name="admin.utilisateurs.desactive-user-account")     * @param KohUtilisateur $kohUtilisateur     * @return RedirectResponse     * @throws Exception     */    public function desactivationUserStructure(KohUtilisateur $kohUtilisateur): RedirectResponse    {        $kohUtilisateur->setIsActived(false);        $kohUtilisateur->setStatus('compte suspendu');        $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));        $this->getDoctrine()->getManager()->flush();        $this->addFlash('success', 'Le compte a été activé');        return $this->redirectToRoute('admin.utilisateurs');    }    /**     * @Route("/admin/structure/utilisateurs/delete/{id}", name="admin.utilisateur.delete", methods={"DELETE"})     * @param KohUtilisateur $kohUtilisateur     * @param Request $request     * @return RedirectResponse     */    public function deleteUserStructure(KohUtilisateur $kohUtilisateur, Request $request): RedirectResponse    {        if ($this->getUser()->getId() === $kohUtilisateur->getId()) {            $this->addFlash('danger', 'Vous ne pouvez pas supprimer votre compte');            return $this->redirectToRoute('admin.utilisateurs');        }        if ($this->isCsrfTokenValid('delete' . $kohUtilisateur->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($kohUtilisateur);            $entityManager->flush();            $this->addFlash('success', 'L\'utilisateur a été supprimé');            return $this->redirectToRoute('admin.utilisateurs');        }        $this->addFlash('danger', 'Vous n\'êtes pas autorisé à effectuer cette opération');        return $this->redirectToRoute('admin.utilisateurs');    }    /**     * @Route("/admin/structure/utilisateurs/edit/{id}", name="admin.utilisateur.edit", methods={"GET", "POST"})     * @param KohUtilisateur $kohUtilisateur     * @param Request $request     * @param UserPasswordEncoderInterface $encoder     * @return Response     * @throws Exception     */    public function editUserStructure(KohUtilisateur $kohUtilisateur, Request $request, UserPasswordEncoderInterface $encoder): Response    {        $form = $this->createForm(KohUtilisateurType::class, $kohUtilisateur);        $form->handleRequest($request);        if ($kohUtilisateur->getId() === $this->getUser()->getId()) {            if ($form->isSubmitted() && $form->isValid()) {                $kohUtilisateur->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));                $kohUtilisateur->setPassword($encoder->encodePassword($kohUtilisateur, $kohUtilisateur->getPassword()));                $this->getDoctrine()->getManager()->flush();                $this->addFlash('success', 'Le compte a été modifié');                return $this->redirectToRoute('admin.utilisateurs');            }            return $this->render('utilisateur_structure/edit_utilisateur_structure.html.twig', ['form' => $form->createView()]);        }        $this->addFlash('danger', 'Vous ne pouvez pas modifier ce compte');        return $this->redirectToRoute('admin.utilisateurs');    }    /**     * @param int $strength     * @return string     */    public function generate_string(int $strength = 16): string    {        $permitted_chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';        $input_length = strlen($permitted_chars);        $random_string = '';        for ($i = 0; $i < $strength; $i++) {            try {                $random_character = $permitted_chars[random_int(0, $input_length - 1)];                $random_string .= $random_character;            } catch (Exception $e) {            }        }        return $random_string;    }}